INSERT INTO `shift` (`shift_code`, `shift_name`, `start_time`, `end_time`, `color`, `description`, `status`) SELECT 'MORNING', '早班', '08:00:00', '16:00:00', '#4CAF50', '早班：8:00 - 16:00', 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `shift` WHERE `shift_code` = 'MORNING');
INSERT INTO `shift` (`shift_code`, `shift_name`, `start_time`, `end_time`, `color`, `description`, `status`) SELECT 'AFTERNOON', '中班', '14:00:00', '22:00:00', '#2196F3', '中班：14:00 - 22:00', 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `shift` WHERE `shift_code` = 'AFTERNOON');
INSERT INTO `shift` (`shift_code`, `shift_name`, `start_time`, `end_time`, `color`, `description`, `status`) SELECT 'NIGHT', '晚班', '22:00:00', '08:00:00', '#9C27B0', '晚班：22:00 - 次日8:00', 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `shift` WHERE `shift_code` = 'NIGHT');
INSERT INTO `shift` (`shift_code`, `shift_name`, `color`, `description`, `status`) SELECT 'REST', '休息', '#9E9E9E', '休息日', 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `shift` WHERE `shift_code` = 'REST');
